/* eslint no-sequences:off */
import styles from "./Modal.module.scss";
import React, { PureComponent, createRef } from "react";
import ReactModal from "react-modal";
import classNames from "classnames";
import { Modals } from "../../../../constants/modals";
import { Key } from "../../../../../common/constants/keyboard";

ReactModal.setAppElement("body");

export default class Modal extends PureComponent {
  ariaHiddenHackSelector = "body>*:not(.ReactModalPortal):not(script)";

  overlayDefaultStyles = {
    zIndex: 100,
    backgroundColor: "rgba(0, 0, 0, 0.6)"
  };

  contentDefaultStyles = {
    left: "50%",
    top: "50%",
    right: "auto",
    bottom: "auto",
    transform: "translate(-50%, -50%)",
    border: "none",
    borderRadius: "10px",
    overflow: "hidden",
    padding: 0
  };

  itemsToHide;
  state = {
    isOpen: false,
    tempHidden: false
  };

  triggerTempHideModal = () => {
    const { tempHidden } = this.state;
    this.setState({
      tempHidden: !tempHidden
    });
  };

  containerElement = createRef();
  wrapperElement = createRef();

  componentDidMount() {
    window.addEventListener("resize", this.onResize);
  }

  componentWillMount() {
    window.removeEventListener("resize", this.onResize);
  }

  onResize = () => {
    const containerElement = this.containerElement.current;
    const wrapperElement = this.wrapperElement.current;

    if (this.state.isOpen && containerElement && wrapperElement) {
      const maxHeight =
        window.innerHeight - containerElement.offsetHeight + wrapperElement.offsetHeight - 10;

      wrapperElement.style.maxHeight = `${maxHeight}px`;
    }
  };

  show(options) {
    document.body.style.overflow = "hidden";
    document.addEventListener("keyup", this.onModalKeyDown);

    this.setState({
      isOpen: true,
      ...options
    });
  }

  hide() {
    document.body.style.removeProperty("overflow");
    document.removeEventListener("keyup", this.onModalKeyDown);
    this.setState({
      isOpen: false
    });
  }

  onOk = e => {
    this.state.ok(e);
    this.onCancel();
  };

  onCancel = () => {
    this.hide();
    if (this.itemsToHide) {
      this.itemsToHide.forEach(item => {
        item.removeAttribute("aria-hidden");
      });
    }

    if (this.props.onCancelClick) {
      this.props.onCancelClick();
    }
    this.itemsToHide = null;
    if (this.state.onCancel) this.state.onCancel();
  };

  onAfterModalOpen = () => {
    this.onResize();
    setTimeout(() => document.body.removeAttribute("aria-hidden"), 0);
    this.itemsToHide = Array.from(document.querySelectorAll(this.ariaHiddenHackSelector)).map(
      item => (item.setAttribute("aria-hidden", "true"), item)
    );
  };

  onModalKeyDown = e => {
    if (e.altKey) {
      switch (e.keyCode) {
        case Key.NUMPAD_SUBTRACT:
        case Key.UNDERSCORE:
          this.onCancel();
          break;
        default:
          break;
      }
    }
  };

  get buttons() {
    const { ok, buttonText } = this.state;
    let buttons = [];

    if (ok) {
      buttons.push(
        <button key="ok" onClick={this.onOk}>
          Ok
        </button>
      );
    }
    buttons.push(
      <button key="cancel" onClick={this.onCancel}>
        {buttonText ? buttonText : "Close"}
      </button>
    );

    return buttons;
  }

  get title() {
    const { title, additionalInfo } = this.state;

    if (title) {
      return (
        <div className={styles.title} aria-hidden="true">
          {title.toUpperCase()}
          <p className={styles.additionalInfo}>{additionalInfo}</p>
        </div>
      );
    }

    return null;
  }

  get dialogModal() {
    const { title, type, isOpen, content, tempHidden, modalAutofocus, label } = this.state;
    const { children } = this.props;
    const contentLabel = title + (content ? ` ${content}` : "");

    return (
      <ReactModal
        contentLabel={contentLabel}
        style={{
          overlay: this.overlayDefaultStyles,
          content: this.contentDefaultStyles
        }}
        aria={{
          label: label
        }}
        isOpen={isOpen}
        onAfterOpen={this.onAfterModalOpen}
        shouldCloseOnOverlayClick={true}
      >
        <div
          style={{
            display: tempHidden ? "none" : ""
          }}
          aria-hidden="false"
          ref={this.containerElement}
          className={classNames(styles.container, styles[`container-${type.toLowerCase()}`])}
          autoFocus={modalAutofocus}
        >
          {this.title}
          <div
            className={classNames(
              styles["content-wrapper"],
              this.state.title && styles["has-title"]
            )}
            ref={this.wrapperElement}
          >
            <div className={classNames(styles.content, styles[`content-${type.toLowerCase()}`])}>
              {children || content}
            </div>
          </div>
          <div className={styles.buttons}>{this.buttons}</div>
        </div>
      </ReactModal>
    );
  }

  get htmlModal() {
    const { title, type, isOpen, content } = this.state;
    const contentLabel = title;

    return (
      <ReactModal
        contentLabel={contentLabel}
        style={{
          overlay: this.overlayDefaultStyles,
          content: this.contentDefaultStyles
        }}
        isOpen={isOpen}
        onAfterOpen={this.onAfterModalOpen}
        shouldCloseOnOverlayClick={true}
      >
        <div
          aria-hidden="false"
          ref={this.containerElement}
          className={classNames(styles.container, styles[`container-${type.toLowerCase()}`])}
        >
          {this.title}
          <div
            className={classNames(
              styles["content-wrapper"],
              this.state.title && styles["has-title"]
            )}
            ref={this.wrapperElement}
          >
            <div
              className={classNames(styles.content, styles[`content-${type.toLowerCase()}`])}
              aria-hidden="true"
              dangerouslySetInnerHTML={{
                __html: content
              }}
              ref={this.onLoadDynamicContent}
            />
          </div>
          <div className={styles.buttons}>{this.buttons}</div>
        </div>
      </ReactModal>
    );
  }

  get imageModal() {
    const { isOpen, imageClassName, source } = this.state;
    const contentStyles = {
      ...this.contentDefaultStyles,
      padding: "0",
      background: "transparent",
      border: "none",
      cursor: "zoom-out"
    };

    return (
      <ReactModal
        style={{
          overlay: this.overlayDefaultStyles,
          content: contentStyles
        }}
        isOpen={isOpen}
        onAfterOpen={this.onAfterModalOpen}
        shouldCloseOnOverlayClick={true}
      >
        <div className={styles.image}>
          <img
            alt=""
            src={source}
            ref={this.containerElement}
            className={imageClassName}
            onClick={this.onCancel}
          />
        </div>
      </ReactModal>
    );
  }

  render() {
    switch (this.state.type) {
      case Modals.DANGER_HTML_CONTENT:
        return this.htmlModal;
      case Modals.DIALOG:
      case Modals.ACTIVITY:
        return this.dialogModal;
      case Modals.IMAGE:
        return this.imageModal;
      default:
        return null;
    }
  }
}
