import styles from "./Button.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import ReactTooltip from "react-tooltip";
import { InjectLocale } from "../../../../decorators/locale";
import { isMobile, isMSBrowser } from "../../../../../common/constants/user-agent";
import { Classes } from "../../../../../common/constants/classes";
import Tooltip from "../../../../../common/components/Tooltip/Tooltip";
import { Key } from "../../../../../common/constants/keyboard";
import { TOOLTIP_CONTAINER } from "../../../../../common/constants/attributes";

@InjectLocale("Button")
class Button extends PureComponent {
  static defaultProps = {
    onKeyDown: () => {},
    onClick: () => {},
    place: "top",
    disableAccessibility: false
  };

  static propTypes = {
    onClick: PropTypes.func,
    onFocus: PropTypes.func,
    onBlur: PropTypes.func,
    onKeyDown: PropTypes.func,
    id: PropTypes.string.isRequired,
    hint: PropTypes.bool,
    place: PropTypes.string,
    className: PropTypes.string,
    notFocusable: PropTypes.bool,
    disabled: PropTypes.bool,
    ariaExpanded: PropTypes.bool,
    ariaPressed: PropTypes.bool,
    disableAccessibility: PropTypes.bool,
    additionArialDescription: PropTypes.string,
    buttonStyle: PropTypes.object
  };

  elementId;

  componentWillMount() {
    const { id } = this.props;
    const date = new Date();

    this.elementId = `${id}-${date.getMilliseconds()}`;
  }

  componentDidUpdate(prevProps) {
    if (isMSBrowser && this.props.className !== prevProps.className) {
      this.refs.button.style.display = "none";
      this.refs.button.style.removeProperty("display");
    }
  }

  onClick = e => {
    e.preventDefault();
    ReactTooltip.hide();
    this.props.onClick(e);
    if (!this.props.disableAccessibility) this.refs.button.focus();
  };

  onKeyPress = e => {
    if (!this.props.disableAccessibility && e.which === Key.SPACEBAR) {
      e.preventDefault();
      this.refs.button.click();
    }
  };

  click() {
    this.refs.button.click();
  }

  focus() {
    this.refs.button.focus();
  }

  render() {
    const {
      className,
      ariaExpanded,
      id,
      children,
      onFocus,
      onBlur,
      onKeyDown,
      notFocusable,
      disableAccessibility,
      disabled,
      hint,
      place,
      ariaPressed,
      additionArialDescription,
      buttonStyle,
      ...rest
    } = this.props;
    const tabIndex = notFocusable || disableAccessibility ? -1 : 0;
    const ariaDescription = this.locale.descriptions[id];
    const ariaLabel = this.locale.labels[id];
    const hintText = this.locale.hints[id];

    return (
      <Tooltip
        id={`tooltip${this.elementId}`}
        text={hintText}
        className={classNames(styles.container, className)}
        type="info"
        effect="solid"
        place={place}
        disable={!hint || isMobile}
        portal={document.getElementById(TOOLTIP_CONTAINER)}
      >
        <div
          ref="button"
          role="button"
          className={styles.button}
          style={buttonStyle}
          aria-pressed={ariaPressed}
          aria-describedby={ariaDescription && `${styles.container}__${this.elementId}`}
          aria-expanded={ariaExpanded}
          aria-label={ariaLabel}
          aria-disabled={disableAccessibility || disabled}
          tabIndex={tabIndex}
          disabled={disabled}
          onFocus={onFocus}
          onBlur={onBlur}
          onClick={this.onClick}
          onKeyDown={onKeyDown}
          onTouchEnd={this.onClick}
          onKeyPress={this.onKeyPress}
          {...rest}
        >
          {(ariaDescription || additionArialDescription) && (
            <span id={`${styles.container}__${this.elementId}`} className={Classes.VISUALLY_HIDDEN}>
              {ariaDescription}
              {additionArialDescription}
            </span>
          )}
          <span
            className={classNames(
              styles["icon-wrapper"],
              disabled && styles["icon-wrapper-disabled"]
            )}
          />
          <span className={styles["text-wrapper"]}>{children}</span>
        </div>
      </Tooltip>
    );
  }
}

export { styles as buttonStyles };
export default Button;
