/* eslint jsx-a11y/anchor-is-valid:off */
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import { Buttons } from "../../../../constants/buttons";
import { Modals } from "../../../../constants/modals";
import Button, { buttonStyles } from "../Button/Button";
import Modal from "../Modal/Modal";
import { Key } from "../../../../../common/constants/keyboard";

export default class Player extends PureComponent {
  static propTypes = {
    displayMode: PropTypes.string.isRequired,
    displaySetting: PropTypes.string.isRequired,
    displayIconImage: PropTypes.string,
    activityName: PropTypes.string.isRequired,
    activityType: PropTypes.string.isRequired
  };

  activityModal;

  showModal = () => {
    this.activityModal.show({
      type: Modals.ACTIVITY
    });
  };

  get activityModalBlock() {
    return <Modal ref={element => (this.activityModal = element)}>{this.activity}</Modal>;
  }

  get activityAlign() {
    const { displayMode, displaySetting } = this.props;

    if (displayMode === "embedded") {
      switch (displaySetting) {
        case "left":
          return {
            marginLeft: 0,
            marginRight: "auto"
          };
        case "right":
          return {
            marginLeft: "auto",
            marginRight: 0
          };
        case "center":
          return {
            marginLeft: "auto",
            marginRight: "auto"
          };
        default:
      }
    }

    return {};
  }

  get showModalButton() {
    const { activityName, activityType, displayIconImage } = this.props;

    return this.props.displayIconImage ? (
      <img
        tabIndex="0"
        role="button"
        src={displayIconImage}
        className={classNames(buttonStyles["show-modal-image"], "popupimagecontainer")}
        alt={activityName}
        aria-label={activityName}
        onTouchStart={this.showModal}
        onClick={this.showModal}
        onKeyPress={e => {
          if (e.which === Key.SPACEBAR) {
            e.preventDefault();
            e.target.click();
          }
        }}
      />
    ) : (
      <Button
        onClick={this.showModal}
        hint={true}
        className={buttonStyles[`show-${activityType.toLowerCase()}`]}
        id={Buttons.SHOW_MODAL}
      >
        {activityName}
      </Button>
    );
  }

  render() {
    const { displayMode, displaySetting } = this.props;

    switch (displayMode) {
      case "embedded":
        return this.activity;
      case "text":
        return (
          <p>
            <a href="#" onClick={this.showModal}>
              {displaySetting}
            </a>
            {this.activityModalBlock}
          </p>
        );
      case "icon":
        return (
          <div style={{ textAlign: displaySetting }}>
            {this.showModalButton}
            {this.activityModalBlock}
          </div>
        );
      default:
    }
  }
}
