/* eslint react/forbid-foreign-prop-types:off */
import "./Tooltip.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import { createPortal } from "react-dom";
import ReactTooltip from "react-tooltip";
import { sleep } from "../../utils/async";

export default class Tooltip extends PureComponent {
  static propTypes = {
    id: PropTypes.string.isRequired,
    text: PropTypes.string.isRequired,
    className: PropTypes.string,
    portal: PropTypes.object,
    onClick: PropTypes.func,
    disable: PropTypes.bool,
    ...ReactTooltip.propTypes
  };

  async reset() {
    ReactTooltip.hide(this.refs.root);
    await sleep(1);
    ReactTooltip.show(this.refs.root);
  }

  render() {
    const { children, id, text, className, onClick, portal, disable, ...rest } = this.props;
    let tooltip = (
      <ReactTooltip {...rest} id={id} ref="tooltip" disable={disable}>
        <span>{text}</span>
      </ReactTooltip>
    );

    if (portal instanceof HTMLElement) {
      tooltip = createPortal(tooltip, portal);
    }

    const props = {
      className,
      onClick,
      "data-tip": true,
      "data-for": id,
      ref: "root"
    };

    return (
      <div {...props}>
        {children}
        {tooltip}
      </div>
    );
  }
}
