/* eslint react/forbid-foreign-prop-types:off */
import PropTypes from "prop-types";
import { LocaleContext } from "../utils/context";

export const InjectLocale = (componentName, defaultLocale) => Component =>
  class extends Component {
    static defaultProps = Component.defaultProps;
    static contextType = LocaleContext;
    static propTypes = {
      ...Component.propTypes,
      locale: PropTypes.object
    };

    get locale() {
      const localeFromContext = this.context[componentName];
      const localeFromProps = this.props.locale;

      return Object.assign({}, defaultLocale, localeFromContext, localeFromProps);
    }
  };
