import { createLogger } from "redux-logger";
import { createStore, applyMiddleware } from "redux";
import { isDevelopment } from "../constants/env";

export class StoreFactory {
  static createStore(initialState, reducers, ...middlewares) {
    if (isDevelopment) {
      middlewares.push(
        createLogger({
          collapsed: true
        })
      );
    }

    const store = createStore(
      ...[
        (state, action) => (reducers[action.type] ? reducers[action.type](state, action) : state),
        initialState,
        middlewares.length && applyMiddleware(...middlewares)
      ].filter(Boolean)
    );

    store.getInitialState = () => initialState;

    return store;
  }

  static createValidatedStore(validator, validationStrategy, ...args) {
    const store = StoreFactory.createStore(...args);

    store.validate = () => validator.validate(store.getState());
    store.asyncValidate = () => {
      return new Promise((resolve, reject) => {
        setTimeout(() => {
          try {
            store.validate(store.getState());
            resolve();
          } catch (e) {
            reject(e);
          }
        }, 0);
      });
    };
    store.fastValidate = () => validator.validate(store.getState(), true);
    store.validator = validator;
    store.validationStrategy = validationStrategy;

    return store;
  }
}
